 5→interface DetailHeaderProps extends SDUIComponentProps {
 6→  icon: string;
 7→  title: string;
 8→  points: string;
 9→  pointsColor?: string;
10→  titleColor?: string;
11→  iconBgColor?: string;
12→  bgColor?: string;
13→}
14→
15→const POINTS_COLOR_MAP: Record<string, string> = {
16→  green: 'PLUS_COLOR_02',
17→  red: 'INTENSE_COLOR_05',
