20→export default function DetailHeaderAdapter({
21→  props,
22→}: {
23→  props: DetailHeaderProps;
24→  context: SDUIContext;
25→}) {
26→  const {
27→    icon,
28→    title,
29→    points,
30→    pointsColor = 'green',
31→    titleColor = 'BRAND_COMPLEMENT_01',
32→    iconBgColor = 'BRAND_COMPLEMENT_03',
