38→  return (
39→    <DetailTransactionValue
40→      icon={icon as never}
41→      title={String(title)}
42→      titleColor={titleColor}
43→      iconBgColor={iconBgColor}
44→      points={String(points)}
45→      bgColor={bgColor}
