 54→describe('SDUI Adapters', () => {
 55→  it('exports all 18 adapters', () => {
 56→    const expected = [
 57→      'heading',
 58→      'text',
 59→      'balance_display',
 60→      'points_input',
 61→      'button',
 62→      'link',
 63→      'alert',
 64→      'list_text_icon',
