 66→      'icon_text_row',
 67→      'section_heading',
 68→      'rich_text',
 69→      'voucher_card',
 70→      'empty_state',
 71→      'points_card',
 72→      'tab_bar',
 73→      'transaction_item',
 74→      'date_separator',
 75→    ];
 76→    expect(Object.keys(adapters)).toEqual(expected);
 77→  });
 78→
 79→  it('registers all adapters to the default registry', () => {
 80→    registerAllAdapters();
 81→    const registry = getDefaultRegistry();
 82→
 83→    Object.keys(adapters).forEach(type => {
 84→      expect(getRenderer(registry, type)).toBeDefined();
 85→    });
 86→  });
 87→
